14095 bool BoUpSLP::collectValuesToDemote(
14096     Value *V, bool IsProfitableToDemoteRoot, unsigned &BitWidth,
14097     SmallVectorImpl<Value *> &ToDemote,
14098     DenseMap<Instruction *, SmallVector<unsigned>> &DemotedConsts,
14099     DenseSet<Value *> &Visited, unsigned &MaxDepthLevel,
14100     bool &IsProfitableToDemote, bool IsTruncRoot) const {
14101   // We can always demote constants.
14102   if (isa<Constant>(V))
14103     return true;
14104 
14105   if (DL->getTypeSizeInBits(V->getType()) == BitWidth) {
14106     MaxDepthLevel = 1;
14107     return true;
14108   }
14109 
14110   // If the value is not a vectorized instruction in the expression and not used
14111   // by the insertelement instruction and not used in multiple vector nodes, it
14112   // cannot be demoted.
14113   auto IsPotentiallyTruncated = [&](Value *V, unsigned &BitWidth) -> bool {
14114     if (MultiNodeScalars.contains(V))
14115       return false;
14116     uint32_t OrigBitWidth = DL->getTypeSizeInBits(V->getType());
14117     if (OrigBitWidth > BitWidth) {
14118       APInt Mask = APInt::getBitsSetFrom(OrigBitWidth, BitWidth);
14119       if (MaskedValueIsZero(V, Mask, SimplifyQuery(*DL)))
14120         return true;
14121     }
14122     auto NumSignBits = ComputeNumSignBits(V, *DL, 0, AC, nullptr, DT);
14123     unsigned BitWidth1 = OrigBitWidth - NumSignBits;
14124     if (!isKnownNonNegative(V, SimplifyQuery(*DL)))
14125       ++BitWidth1;
14126     BitWidth = std::max(BitWidth, BitWidth1);
14127     return BitWidth > 0 && OrigBitWidth >= (BitWidth * 2);
14128   };
14129   auto FinalAnalysis = [&](const TreeEntry *ITE = nullptr) {
14130     if (!IsProfitableToDemote)
14131       return false;
14132     return (ITE && ITE->UserTreeIndices.size() > 1) ||
14133            IsPotentiallyTruncated(V, BitWidth);
14134   };
14135   // TODO: improve handling of gathered values and others.
14136   auto *I = dyn_cast<Instruction>(V);
14137   const TreeEntry *ITE = I ? getTreeEntry(I) : nullptr;
14138   if (!ITE || !Visited.insert(I).second || MultiNodeScalars.contains(I) ||
14139       all_of(I->users(), [&](User *U) {
14140         return isa<InsertElementInst>(U) && !getTreeEntry(U);
14141       }))
14142     return FinalAnalysis();
14143 
14144   unsigned Start = 0;
14145   unsigned End = I->getNumOperands();
14146 
14147   auto ProcessOperands = [&](ArrayRef<Value *> Operands, bool &NeedToExit) {
14148     NeedToExit = false;
14149     unsigned InitLevel = MaxDepthLevel;
14150     for (Value *IncValue : Operands) {
14151       unsigned Level = InitLevel;
14152       if (!collectValuesToDemote(IncValue, IsProfitableToDemoteRoot, BitWidth,
14153                                  ToDemote, DemotedConsts, Visited, Level,
14154                                  IsProfitableToDemote, IsTruncRoot)) {
14155         if (!IsProfitableToDemote)
14156           return false;
14157         NeedToExit = true;
14158         if (!FinalAnalysis(ITE))
14159           return false;
14160         continue;
14161       }
14162       MaxDepthLevel = std::max(MaxDepthLevel, Level);
14163     }
14164     return true;
14165   };
14166   auto AttemptCheckBitwidth =
14167       [&](function_ref<bool(unsigned, unsigned)> Checker, bool &NeedToExit) {
14168         // Try all bitwidth < OrigBitWidth.
14169         NeedToExit = false;
14170         uint32_t OrigBitWidth = DL->getTypeSizeInBits(I->getType());
14171         unsigned BestFailBitwidth = 0;
14172         for (; BitWidth < OrigBitWidth; BitWidth *= 2) {
14173           if (Checker(BitWidth, OrigBitWidth))
14174             return true;
14175           if (BestFailBitwidth == 0 && FinalAnalysis())
14176             BestFailBitwidth = BitWidth;
14177         }
14178         if (BitWidth >= OrigBitWidth) {
14179           if (BestFailBitwidth == 0) {
14180             BitWidth = OrigBitWidth;
14181             return false;
14182           }
14183           MaxDepthLevel = 1;
14184           BitWidth = BestFailBitwidth;
14185           NeedToExit = true;
14186           return true;
14187         }
14188         return false;
14189       };
14190   auto TryProcessInstruction =
14191       [&](Instruction *I, const TreeEntry &ITE, unsigned &BitWidth,
14192           ArrayRef<Value *> Operands = std::nullopt,
14193           function_ref<bool(unsigned, unsigned)> Checker = {}) {
14194         if (Operands.empty()) {
14195           if (!IsTruncRoot)
14196             MaxDepthLevel = 1;
14197           (void)IsPotentiallyTruncated(V, BitWidth);
14198         } else {
14199           // Several vectorized uses? Check if we can truncate it, otherwise -
14200           // exit.
14201           if (ITE.UserTreeIndices.size() > 1 &&
14202               !IsPotentiallyTruncated(I, BitWidth))
14203             return false;
14204           bool NeedToExit = false;
14205           if (Checker && !AttemptCheckBitwidth(Checker, NeedToExit))
14206             return false;
14207           if (NeedToExit)
