14223       };
14224   switch (I->getOpcode()) {
14225 
14226   // We can always demote truncations and extensions. Since truncations can
14227   // seed additional demotion, we save the truncated value.
14228   case Instruction::Trunc:
14229     if (IsProfitableToDemoteRoot)
14230       IsProfitableToDemote = true;
